import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

describe('Dirty database read stream encoding', () => {
  it('should correctly parse entries when multi-byte UTF-8 characters span chunk boundaries', (done) => {
    const tmpDir = os.tmpdir();
    const dbPath = path.join(tmpDir, `dirty-chunk-test-${process.pid}.db`);

    const CHUNK_SIZE = 65536; // default highWaterMark for fs.createReadStream

    // Place 4-byte emoji 🎉 (F0 9F 8E 89) starting at byte CHUNK_SIZE - 2
    // so 2 bytes fall in chunk 1 and 2 bytes fall in chunk 2
    // Without encoding, this causes Buffer.toString() to emit replacement chars
    // With encoding: 'utf-8', StringDecoder handles the boundary correctly

    const row1Prefix = '{"key":"pad","val":"';
    const row1Suffix = '"}\n';
    const targetRow1Length = CHUNK_SIZE - 2;
    const paddingLength = targetRow1Length - Buffer.byteLength(row1Prefix) - Buffer.byteLength(row1Suffix);

    const row1 = row1Prefix + 'A'.repeat(paddingLength) + row1Suffix;
    const row2 = '{"key":"emoji","val":"🎉"}\n';

    fs.writeFileSync(dbPath, row1 + row2, 'utf-8');

    const Dirty = require('../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js');
    const db = new Dirty(dbPath);

    const errors: Error[] = [];
    db.on('error', (err: Error) => errors.push(err));

    db.on('load', () => {
      try {
        fs.unlinkSync(dbPath);
        expect(errors).toHaveLength(0);
        expect(db.get('emoji')).toBe('🎉');
        done();
      } catch (e) {
        try { fs.unlinkSync(dbPath); } catch {}
        done(e);
      }
    });
  });
});
